{"statement":{"value":"-- Same set via NOT EXISTS — preferred when product table is large
SELECT p.product_id, p.product_name, p.product_status, p.date_added
FROM   order_entry_db.order_entry.products p
WHERE  NOT EXISTS (
           SELECT 1 FROM order_entry_db.order_entry.order_items oi
           WHERE oi.product_id = p.product_id
       )
ORDER  BY p.date_added DESC;
","language":"SQL"},"source":"MANUAL","created":{"time":1740376750731,"actor":"urn:li:corpuser:b2fd91.sam@example.com"},"lastModified":{"time":1741841950731,"actor":"urn:li:corpuser:b2fd91.sam@example.com"},"name":"products_never_ordered/02-not_exists_version","description":"Which products in our catalogue have never been ordered?","origin":"urn:li:corpuser:b2fd91.sam@example.com"}

{"statement":{"value":"-- Same set via NOT IN (note: only safe if order_items.product_id has no NULLs)
