{"statement":{"value":"-- Delivery type revenue via mart
-- Author: James Wilson

with hdr as (
    select order_id, any_value(delivery_type) as dt, any_value(order_total) as total,
           any_value(cost_of_delivery) as ship, any_value(order_status) as status
    from order_entry_db.analytics.order_details group by order_id
)
select dt as delivery_type, count(*) as orders, sum(total) as revenue, sum(ship) as shipping_cost
from hdr where status not in (3, 4)
group by 1 order by revenue desc;
","language":"SQL"},"source":"MANUAL","created":{"time":1743288419854,"actor":"urn:li:corpuser:b2fd91.jonny2@example.com"},"lastModified":{"time":1743374819854,"actor":"urn:li:corpuser:b2fd91.jonny2@example.com"},"name":"revenue_by_delivery_type/02-mart_version","description":"What is the revenue split by delivery method (standard, express, overnight, ...)","origin":"urn:li:corpuser:b2fd91.jonny2@example.com"}

{"statement":{"value":"-- Channel revenue via the mart
-- Author: James Wilson

with hdr as (
    select order_id, any_value(order_mode) as order_mode, any_value(order_total) as order_total, any_value(order_status) as order_status
